import {
  circle, ellipse, rectangle, polygon, segment,
  union, intersection, difference, dilate, shell,
  render,
} from '../../src/index.js';

// --- Palette ---
const CREAM      = [245, 238, 220];
const CELADON    = [168, 198, 178];
const CELADON_D  = [120, 158, 138];
const CELADON_L  = [210, 228, 215];
const RIM        = [ 90, 120, 105];
const OUTLINE    = [ 32,  28,  22];
const BG_TOP     = [240, 232, 215];
const BG_BOT     = [215, 205, 188];

// --- Vase profile (hand-traced, right half x≥0, y = height) ---
// Neck → shoulder → belly → foot → base
const vaseProfile = polygon([
  // base rim (right)
  [ 0.000, -0.70],
  [ 0.180, -0.70],
  [ 0.200, -0.64],
  // foot curve
  [ 0.210, -0.58],
  [ 0.190, -0.50],
  // lower belly — widest point
  [ 0.280, -0.20],
  [ 0.310,  0.05],
  [ 0.290,  0.20],
  // shoulder
  [ 0.220,  0.38],
  [ 0.160,  0.50],
  // neck
  [ 0.120,  0.56],
  [ 0.100,  0.62],
  // lip flare
  [ 0.130,  0.68],
  [ 0.145,  0.72],
  // centre-line (top)
  [ 0.000,  0.72],
  // mirror left side
  [-0.145,  0.72],
  [-0.130,  0.68],
  [-0.100,  0.62],
  [-0.120,  0.56],
  [-0.160,  0.50],
  [-0.220,  0.38],
  [-0.290,  0.20],
  [-0.310,  0.05],
  [-0.280, -0.20],
  [-0.190, -0.50],
  [-0.210, -0.58],
  [-0.200, -0.64],
  [-0.180, -0.70],
]);

// --- Interior cavity (mouth opening) ---
const mouth = ellipse(0.12, 0.025, [0, 0.70]);

// --- Decorative band: horizontal stripe clipped to vase ---
const stripe1 = intersection(
  vaseProfile,
  rectangle([1.0, 0.055], [0, 0.10]),
);
const stripe2 = intersection(
  vaseProfile,
  rectangle([1.0, 0.030], [0, -0.35]),
);

// --- Rim ring at lip ---
const rimRing = intersection(
  vaseProfile,
  rectangle([1.0, 0.045], [0, 0.68]),
);

// --- Highlight: a vertical soft ellipse on the left shoulder ---
const highlight = intersection(
  vaseProfile,
  ellipse(0.055, 0.16, [-0.16, 0.28]),
);

// --- Shadow: right-side crescent using difference ---
const shadowBand = intersection(
  vaseProfile,
  difference(
    ellipse(0.35, 0.72, [0.10, 0]),
    ellipse(0.22, 0.60, [-0.02, 0]),
  ),
);

// --- Base shadow ellipse on ground ---
const baseShadow = ellipse(0.26, 0.04, [0, -0.73]);

// --- Assemble layers ---
const layers = [
  // ground shadow
  { sdf: baseShadow,                  color: [180, 168, 148] },

  // vase body outline (dilate idiom)
  { sdf: dilate(vaseProfile, 0.028),  color: OUTLINE },

  // vase body fill
  { sdf: vaseProfile,                 color: CELADON },

  // dark shadow band on right
  { sdf: shadowBand,                  color: CELADON_D },

  // decorative stripes
  { sdf: stripe2,                     color: RIM },
  { sdf: stripe1,                     color: RIM },
  { sdf: rimRing,                     color: RIM },

  // highlight sliver
  { sdf: highlight,                   color: CELADON_L },

  // mouth opening (dark cavity)
  { sdf: dilate(mouth, 0.012),        color: OUTLINE },
  { sdf: mouth,                       color: [55, 45, 38] },
];

// --- Render ---
const canvas = document.getElementById('c');
const ctx    = canvas.getContext('2d');
render.silhouette(ctx, layers, {
  view: 1.0,
  background: { top: BG_TOP, bottom: BG_BOT },
});
```

**Composition notes:**

The vase is built as a single hand-traced `polygon` — 28 vertices symmetric on the centre axis — giving it a classical Chinese *mei ping* silhouette: wide belly, cinched foot, flared lip. The outline-via-`dilate` idiom (0.028 world units) gives it the weighty editorial border. Celadon green was chosen over a literal terracotta because it reads "Chinese porcelain" instantly and the three-value (light / mid / dark) colour split (`CELADON_L` / `CELADON` / `CELADON_D`) creates convincing volume without actual shading. The shadow band is an `intersection` of the vase with a crescent (two overlapping ellipses, `difference`), placing the darkest tone on the right shoulder and belly. The two horizontal `RIM`-coloured stripes and lip ring recall the painted decorative bands on Song-dynasty celadons. The mouth is a tiny dark ellipse at the top — just enough to suggest depth inside the opening.
